// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, response_type, state } = req.query;
  
  if (!client_id || !redirect_uri || !response_type) {
    return res.status(400).json({ error: 'Invalid request' });
  }
  
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'Invalid client' });
  }
  
  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'Invalid redirect URI' });
  }
  
  if (response_type !== 'code') {
    return res.status(400).json({ error: 'Invalid response type' });
  }
  
  if (!req.session.user) {
    return res.redirect('/login');
  }
  
  // Generate authorization code
  const code = crypto.randomBytes(32).toString('hex');
  const codeData = {
    client_id,
    redirect_uri,
    state,
    user_id: req.session.user.id,
    expires_at: Date.now() + 300000 // 5 minutes
  };
  
  authorizationCodes.set(code, codeData);
  
  const redirectUrl = `${redirect_uri}?code=${code}`;
  if (state) {
    redirectUrl += `&state=${state}`;
  }
  
  res.redirect(redirectUrl);
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, client_id, client_secret, code, redirect_uri } = req.body;
  
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'Invalid grant type' });
  }
  
  const client = clients.get(client_id);
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'Invalid client credentials' });
  }
  
  if (!code) {
    return res.status(400).json({ error: 'Missing authorization code' });
  }
  
  const codeData = authorizationCodes.get(code);
  if (!codeData) {
    return res.status(400).json({ error: 'Invalid authorization code' });
  }
  
  if (codeData.expires_at < Date.now()) {
    return res.status(400).json({ error: 'Authorization code expired' });
  }
  
  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'Invalid redirect URI' });
  }
  
  // Generate access token
  const accessToken = crypto.randomBytes(32).toString('hex');
  const tokenData = {
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    client_id,
    user_id: codeData.user_id,
    created_at: Date.now()
  };
  
  accessTokens.set(accessToken, tokenData);
  
  // Remove used authorization code
  authorizationCodes.delete(code);
  
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600
  });
});

// Protected route example
app.get('/api/profile', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or invalid token' });
  }
  
  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);
  
  if (!tokenData) {
    return res.status(401).json({ error: 'Invalid token' });
  }
  
  res.json({ 
    user_id: tokenData.user_id,
    client_id: tokenData.client_id
  });
});

